import { useState, useEffect, useContext, useRef } from "react"
import AppContext from "../../context"
import css from "./Master.module.css"
import Card from "../../components/Card/Card"
import backgroundCard from "../../assets/images/backgroundCardBlue.jpg"
import Popup from "../../components/Popup/Popup"
import { FaEdit } from "react-icons/fa"
import { FormBusinessUnitEntity, BusinessUnitEntity } from "../../entities/BusinessUnitEntity"
import ExcelUtils from "../../utils/excel"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaSortDown, FaSortUp } from "react-icons/fa6"
import filterUtils from "../../utils/filter-utils"
import { GrPowerReset } from "react-icons/gr"
import { BusinessUnitService } from "../../services/business_unit"
import PopupInputData from "../../components/InputData/InputDataElement"
import { BusinessUnitConfig, FormBusinessUnitCenterline } from "../../entities/CenterlineEntity"
import { CenterlineService } from "../../services/centerline"

export default function MasterBusinessUnit() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    interface BusinessUnitCombined extends BusinessUnitEntity, BusinessUnitConfig { }

    const [tableData, setTableData] = useState<BusinessUnitCombined[]>([])
    const [tableDataCache, setTableDataCache] = useState<BusinessUnitCombined[]>([])

    const [selectedData, setSelectedData] = useState<BusinessUnitCombined | null>(null)
    const [formData, setFormData] = useState<FormBusinessUnitEntity | null>(null)
    const [formDataCenterline, setFormDataCenterline] = useState<FormBusinessUnitCenterline | null>(null)

    const [showPopup, setShowPopup] = useState(false)

    const [sortColumn, setSortColumn] = useState<keyof BusinessUnitCombined | null>(null)
    const [sortType, setSortType] = useState<"ascending" | "descending">("ascending")
    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})
    // ========================================= STATE VIEW =========================================  //

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    // TABLE AND FORMS //
    const resetAllForm = () => {
        setFormData(null)
        setFormDataCenterline(null)
    }

    const handleShowPopup = (row?: BusinessUnitCombined) => {
        setSelectedData(row ?? null)
        resetAllForm()
        setShowPopup(true)
    }

    const handleFilterAndSort = async () => {
        const resp = tableDataCache
        let table_filtered = resp.filter((row) => {
            return filterUtils.FilterTable(row, tableDataFilter)
        }).sort((a, b) => {
            if (!sortColumn) return 0
            if (sortType == "ascending") {
                return filterUtils.SortingTable(a, b, sortColumn)
            } else {
                return filterUtils.SortingTable(b, a, sortColumn)
            }
        })

        setTableData(table_filtered)
    }

    const filterTable = (column: keyof BusinessUnitCombined, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", maxWidth: "500px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }

    const headerTable = (column: keyof BusinessUnitCombined, columnName?: string) => {
        return <>
            <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
                onClick={() => {
                    setSortColumn(column)
                    if (sortType === "ascending") {
                        setSortType("descending")
                    } else {
                        setSortType("ascending")
                    }
                }}
            >
                <div>{columnName ?? column}</div>
                <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}
                >
                    <FaSortUp style={{ color: ((sortColumn == column && sortType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                    <FaSortDown style={{ color: ((sortColumn == column && sortType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
                </div>
            </div>
        </>
    }

    useEffect(() => {
        handleFilterAndSort()
    }, [tableDataFilter, sortColumn, sortType])

    // TABLE AND FORMS //

    // CRUD SERVICES //
    const handleSaveAdd = async () => {
        contextShowLoadingFunc(true)

        try {
            if (formData == null) { throw new Error("Please fill all forms!") }
            if (formData.business_unit == null) { throw new Error("Please fill business_unit!") }
            if (formData.business_unit_warn == null) { throw new Error("Please fill business_unit_warn!") }
            if (formData.business_unit_alarm == null) { throw new Error("Please fill business_unit_alarm!") }

            const resp = await BusinessUnitService.AddBusinessUnit({
                business_unit: formData.business_unit,
                business_unit_warn: formData.business_unit_warn,
                business_unit_alarm: formData.business_unit_alarm
            })

            await generateData()
            setSelectedData(null)
            resetAllForm()
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleSaveUpdate = async () => {
        contextShowLoadingFunc(true)

        try {
            if (selectedData == null) { throw new Error("Please fill in all forms!") }

            if (formData != null) {
                await BusinessUnitService.UpdateBusinessUnit(selectedData.business_unit_id, formData)
            }
            if (contextVersion.centerline != null && formDataCenterline != null) {
                await CenterlineService.UpsertBusinessUnitConfig(selectedData.business_unit_id, formDataCenterline)
            }

            await generateData()
            setSelectedData(null)
            resetAllForm()
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: "[Success]", level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleDelete = async () => {
        return contextShowAlertFunc(new AlertEntity({
            message: `Are you sure you want to delete ${selectedData?.business_unit} ?`,
            onOk: async () => {
                contextShowLoadingFunc(true)

                try {
                    if (selectedData == null) return
                    const resp = await BusinessUnitService.DeleteBusinessUnit(selectedData.business_unit_id)

                    await generateData()
                    setSelectedData(null)
                    setShowPopup(false)
                    contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
                } catch (error: any) {
                    contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
                } finally {
                    contextShowLoadingFunc(false)
                }
            },
            withCancel: true,
            withOk: true,
            level: 2
        }))
    }

    const generateData = async () => {
        contextShowLoadingFunc(true)

        try {
            const resp = await BusinessUnitService.GetAllBusinessUnit()
            if (contextVersion.centerline != null) {
                const foll = await CenterlineService.GetBusinessUnitConfig()
                const mapped: { [business_unit_id: number]: BusinessUnitConfig } = {}
                for (let i = 0; i < foll.length; i++) {
                    mapped[foll[i].business_unit_id] = foll[i]
                }

                for (let i = 0; i < resp.length; i++) {
                    resp[i] = { ...resp[i], ...mapped[resp[i].business_unit_id] }
                }
            }

            setTableData(resp)
            setTableDataCache(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    useEffect(() => {
        generateData()
    }, [contextAccessToken])

    // CRUD SERVICES //

    // IMPORT EXPORT EXCEL //
    const handleGenerateExcel = async () => {
        if (tableData.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = ["business_unit", "business_unit_warn", "business_unit_alarm"]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableData.length; i++) {
            values.push({
                business_unit: tableData[i].business_unit,
                business_unit_warn: tableData[i].business_unit_warn.toString() ?? '',
                business_unit_alarm: tableData[i].business_unit_alarm.toString() ?? '',
            })
        }

        ExcelUtils.export(`Master Business Unit List`, column, values)
    }

    // IMPORT EXPORT EXCEL //

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    return <>
        <div className="container" style={{ display: stateShowLoading ? "none" : "flex", backgroundColor: "transparent" }}>

            <div style={{ height: "94dvh", maxHeight: "100vh", display: "flex", flexDirection: "column" }}>

                {/* Card Header */}
                <div style={{ flexBasis: "auto" }} className="ordering-card">
                    <Card
                        detailTitle="Master Business Unit"
                        detailColor="var(--secondary-color)"
                        backgroundImage={backgroundCard}
                        stateShow={true}
                        detailCard={
                            <>
                                <div className={css.rowGrid} style={{ alignItems: 'end' }}>
                                    <div>
                                        <div style={{ color: "white", textAlign: "start" }}>Action :</div>
                                        <button className="cardButton" onClick={() => handleShowPopup()} >
                                            Add New
                                        </button>
                                    </div>
                                    <div>
                                        <button className="cardButton" onClick={() => handleGenerateExcel()} >
                                            Generate Excel
                                        </button>
                                    </div>
                                    <div>
                                        <button className="cardButton" onClick={() => { setTableDataFilter({}); generateData(); setSortColumn(null); setSortType("descending") }} >
                                            <GrPowerReset /> &nbsp; Reset Filter
                                        </button>
                                    </div>
                                </div>
                            </>
                        }
                    />
                </div>

                {/* Table */}
                <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                    <table className="tableclickcell">
                        <thead>
                            <tr>
                                <th colSpan={4}>MASTER BUSINESS UNIT</th>
                                {contextVersion.centerline != null && <th colSpan={2}>CENTERLINE</th>}
                                <th rowSpan={2} style={{ backgroundColor: "var(--header-color)", width: "7dvw", maxWidth: "7dvw", minWidth: "7dvw", position: "sticky", right: 0, zIndex: 1 }}>Action</th>
                            </tr>
                            <tr>
                                <th>No</th>
                                <th>
                                    {headerTable("business_unit", "Business Unit")}
                                    {filterTable("business_unit", "Business Unit")}
                                </th>
                                <th>
                                    {headerTable("business_unit_warn", "Business Unit Warn")}
                                    {filterTable("business_unit_warn", "Business Unit Warn")}
                                </th>
                                <th>
                                    {headerTable("business_unit_alarm", "Business Unit Alarm")}
                                    {filterTable("business_unit_alarm", "Business Unit Alarm")}
                                </th>
                                {contextVersion.centerline != null && <>
                                    <th>
                                        {headerTable("centerline_warn", "Centerline Warn")}
                                        {filterTable("centerline_warn", "Centerline Warn")}
                                    </th>
                                    <th>
                                        {headerTable("centerline_alarm", "Centerline Alarm")}
                                        {filterTable("centerline_alarm", "Centerline Alarm")}
                                    </th>
                                </>}
                            </tr>
                        </thead>
                        {tableData.length > 0
                            ? <tbody>
                                {tableData.map((row, index) => {
                                    return (
                                        <tr key={index}>
                                            <td>{index + 1}</td>
                                            <td>{row.business_unit}</td>
                                            <td>{row.business_unit_warn}</td>
                                            <td>{row.business_unit_alarm}</td>

                                            {/* CENTERLINE */}
                                            {contextVersion.centerline != null && <>
                                                <td>{row.centerline_warn}</td>
                                                <td>{row.centerline_alarm}</td>
                                            </>}

                                            <td className="group-pick" onClick={() => { handleShowPopup(row) }}>
                                                <FaEdit /> Edit
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                            : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                        }
                    </table>
                </div>

            </div>


            {/* Popup Detail */}
            <Popup
                setShowPopup={setShowPopup}
                showPopup={showPopup}
                popupTitle={selectedData == null ? "Add New" : `Edit ${selectedData?.business_unit}`}
                popupContent={<>
                    <div className={css.bodyPopup}>
                        <div className={`${selectedData == null ? css.containerleftright : css.containerForm}`}>
                            {/* MASTER */}
                            <div className={`${selectedData == null ? css.leftposition : css.containerFormItem}`}>
                                <PopupInputData
                                    label={"Business Unit"} type_input={"text"} value={formData?.business_unit} original_value={selectedData?.business_unit ?? ''}
                                    attribute={"business_unit"} required={true} setFormData={setFormData}
                                />
                                <PopupInputData
                                    label={"Business Unit Warn"} type_input={"number"} value={formData?.business_unit_warn} original_value={selectedData?.business_unit_warn ?? ''}
                                    attribute={"business_unit_warn"} required={true} setFormData={setFormData}
                                />
                                <PopupInputData
                                    label={"Business Unit Alarm"} type_input={"number"} value={formData?.business_unit_alarm} original_value={selectedData?.business_unit_alarm ?? ''}
                                    attribute={"business_unit_alarm"} required={true} setFormData={setFormData}
                                />
                            </div>

                            {/* CENTERLINE */}
                            {contextVersion.centerline != null && selectedData != null && (
                                <>
                                    <div style={{ marginTop: "15px", marginBottom: "10px", width: "100%", height: "5px", backgroundColor: "#2d545e" }}></div>

                                    <div className={css.containerFormItem}>
                                        <PopupInputData
                                            label={"Centerline Warn"} type_input={"number"} value={formDataCenterline?.centerline_warn} original_value={selectedData?.centerline_warn ?? ''}
                                            attribute={"centerline_warn"} required={true} setFormData={setFormDataCenterline}
                                        />
                                        <PopupInputData
                                            label={"Centerline Alarm"} type_input={"number"} value={formDataCenterline?.centerline_alarm} original_value={selectedData?.centerline_alarm ?? ''}
                                            attribute={"centerline_alarm"} required={true} setFormData={setFormDataCenterline}
                                        />
                                    </div>
                                </>
                            )}
                        </div>
                    </div>

                    <div className={css.footerPopup}>
                        <div className={css.buttons2}>
                            <div className={css.left}>
                                <button className="tertiaryButton" onClick={() => { setShowPopup(false) }} >
                                    Close
                                </button>
                            </div>
                            {selectedData &&
                                <div className={css.right}>
                                    <button className="secondaryButton" onClick={() => handleDelete()}>
                                        Delete
                                    </button>
                                </div>
                            }
                            <div className={css.right}>
                                <button className="primaryButton"
                                    onClick={() => { selectedData ? handleSaveUpdate() : handleSaveAdd() }} >
                                    Save
                                </button>
                            </div>
                        </div>
                    </div>
                </>
                }
            />
        </div>
    </>
}
